INSERT INTO lessons (language_code, cefr_level, skill, title, title_translation, description, description_translation, content, order_index) VALUES
('de', 'A1', 'listening', 'Zahlen hören', 'Listening to Numbers', 'Hören Sie die Zahlen im Kontext.', 'Listen to numbers in context.', '{"type":"listen_and_choose","instructions":"Welche Zahl haben Sie gehört?","exercises":[{"prompt":"Das Ticket kostet fünfundsiebzig Euro.","question":"Wie viel kostet das Ticket?","options":["25","57","75"],"correct":2,"hint":"Fünf und siebzig."},{"prompt":"Ich wohne in der Hausnummer zweiundvierzig.","question":"Welche Hausnummer?","options":["24","42","52"],"correct":1,"hint":"Zwei und vierzig."},{"prompt":"Der Bus kommt in achtzehn Minuten.","options":["8","18","80"],"correct":1,"hint":"Achtzehn (-zehn is teen)."},{"prompt":"Wir haben dreiunddreißig Teilnehmer.","question":"Wie viele Teilnehmer?","options":["13","33","23"],"correct":1,"hint":"Drei und dreißig."},{"prompt":"Das Kleid kostet neunundneunzig Euro.","question":"Preis?","options":["19","89","99"],"correct":2,"hint":"Neun und neunzig."},{"prompt":"Der Film dauert zwei Stunden.","question":"Wie lange dauert der Film?","options":["1","2","3"],"correct":1,"hint":"Zwei Stunden."},{"prompt":"Ich habe fünf Äpfel gekauft.","question":"Wie viele Äpfel habe ich gekauft?","options":["3","5","7"],"correct":1,"hint":"Fünf."},{"prompt":"Das Buch kostet dreißig Euro.","question":"Wie viel kostet das Buch?","options":["20","30","40"],"correct":1,"hint":"Dreißig."},{"prompt":"Ich habe vier Geschwister.","question":"Wie viele Geschwister habe ich?","options":["2","4","6"],"correct":1,"hint":"Vier."},{"prompt":"Wir treffen uns um sechzehn Uhr.","question":"Um wie viel Uhr treffen wir uns?","options":["14","16","18"],"correct":1,"hint":"Sechzehn Uhr."},{"prompt":"Die Klasse hat dreißig Schüler.","question":"Wie viele Schüler hat die Klasse?","options":["25","30","35"],"correct":1,"hint":"Dreißig."},{"prompt":"Ich habe einen Hund und zwei Katzen.","question":"Wie viele Katzen habe ich?","options":["1","2","3"],"correct":1,"hint":"Zwei Katzen."},{"prompt":"Der Zug fährt um zehn Uhr.","question":"Wann fährt der Zug?","options":["9","10","11"],"correct":1,"hint":"Zehn Uhr."},{"prompt":"Ich habe sieben Euro in meiner Tasche.","question":"Wie viel Geld habe ich?","options":["5","7","9"],"correct":1,"hint":"Sieben Euro."},{"prompt":"Wir essen um zwanzig Uhr.","question":"Wann essen wir?","options":["18","20","22"],"correct":1,"hint":"Zwanzig Uhr."},{"prompt":"Es gibt zwölf Monate im Jahr.","question":"Wie viele Monate gibt es im Jahr?","options":["10","12","14"],"correct":1,"hint":"Zwölf Monate."},{"prompt":"Ich habe einen Termin um neunzehn Uhr.","question":"Um wie viel Uhr ist der Termin?","options":["17","19","21"],"correct":1,"hint":"Neunzehn Uhr."},{"prompt":"Das Konzert beginnt um halb acht.","question":"Wann beginnt das Konzert?","options":["6:30","7:30","8:30"],"correct":1,"hint":"Halb acht."},{"prompt":"Ich trinke drei Tassen Kaffee pro Tag.","question":"Wie viele Tassen Kaffee trinke ich?","options":["2","3","4"],"correct":1,"hint":"Drei Tassen."},{"prompt":"Es sind fünfzehn Grad draußen.","question":"Wie viel Grad sind es draußen?","options":["10","15","20"],"correct":1,"hint":"Fünfzehn Grad."}]}', 11),
('de', 'A1', 'listening', 'Uhrzeiten verstehen', 'Understanding Times', 'Hören Sie offizielle und inoffizielle Uhrzeiten.', 'Listen to official and informal times.', '{"type":"listen_and_choose","instructions":"Wie spät ist es?","exercises":[{"prompt":"Es ist halb neun.","question":"Uhrzeit?","options":["8:30","9:30","7:30"],"correct":0,"hint":"Halb neun means halfway to nine (8:30)."},{"prompt":"Der Zug fährt um Viertel vor zehn.","question":"Wann fährt der Zug?","options":["9:15","9:45","10:15"],"correct":1,"hint":"Viertel vor means quarter to."},{"prompt":"Der Kurs beginnt um acht Uhr fünfzehn.","question":"Beginn?","options":["8:15","8:50","7:15"],"correct":0,"hint":"Acht Uhr fünfzehn."},{"prompt":"Es ist kurz nach zwölf.","question":"Uhrzeit?","options":["11:55","12:05","12:30"],"correct":1,"hint":"Short after twelve."},{"prompt":"Das Konzert ist um Viertel nach eins.","question":"Beginn?","options":["12:45","1:15","2:15"],"correct":1,"hint":"Viertel nach means quarter past."},{"prompt":"Es ist zehn Uhr dreißig.","question":"Uhrzeit?","options":["10:30","11:30","9:30"],"correct":0,"hint":"Zehn Uhr dreißig means ten thirty."},{"prompt":"Der Film beginnt um zwanzig Uhr.","question":"Wann beginnt der Film?","options":["8:00 PM","7:00 PM","9:00 PM"],"correct":0,"hint":"Zwanzig Uhr is 8 PM in 24-hour format."},{"prompt":"Es ist fünf nach halb sechs.","question":"Uhrzeit?","options":["5:25","5:35","6:05"],"correct":1,"hint":"Fünf nach halb sechs means five minutes past half past five."},{"prompt":"Das Meeting ist um Viertel nach drei.","question":"Wann ist das Meeting?","options":["2:15","3:15","3:45"],"correct":1,"hint":"Viertel nach means quarter past."},{"prompt":"Es ist zwanzig nach eins.","question":"Uhrzeit?","options":["1:20","1:40","2:20"],"correct":0,"hint":"Zwanzig nach eins means twenty past one."},{"prompt":"Der Unterricht beginnt um neun Uhr.","question":"Beginn?","options":["8:00","9:00","10:00"],"correct":1,"hint":"Neun Uhr means nine o''clock."},{"prompt":"Es ist drei Viertel acht.","question":"Uhrzeit?","options":["7:45","8:45","6:45"],"correct":0,"hint":"Drei Viertel acht means three quarters to eight (7:45)."},{"prompt":"Der Flug geht um halb fünf.","question":"Wann geht der Flug?","options":["4:30","5:30","3:30"],"correct":0,"hint":"Halb fünf means half past four."},{"prompt":"Es ist zehn Minuten vor zwei.","question":"Uhrzeit?","options":["1:50","2:10","12:50"],"correct":0,"hint":"Zehn Minuten vor zwei means ten minutes to two."},{"prompt":"Die Party beginnt um halb sieben.","question":"Wann beginnt die Party?","options":["6:30","7:30","5:30"],"correct":0,"hint":"Halb sieben means half past six."},{"prompt":"Es ist Viertel nach fünf.","question":"Uhrzeit?","options":["5:15","5:45","6:15"],"correct":0,"hint":"Viertel nach means quarter past."},{"prompt":"Der Termin ist um zwei Uhr.","question":"Wann ist der Termin?","options":["1:00","2:00","3:00"],"correct":1,"hint":"Zwei Uhr means two o''clock."},{"prompt":"Es ist fünf Uhr.","question":"Uhrzeit?","options":["5:00","4:00","6:00"],"correct":0,"hint":"Fünf Uhr means five o''clock."},{"prompt":"Der Zug kommt um zehn nach sieben.","question":"Wann kommt der Zug?","options":["7:10","6:10","8:10"],"correct":0,"hint":"Zehn nach sieben means ten past seven."},{"prompt":"Es ist zwei Uhr zwanzig.","question":"Uhrzeit?","options":["2:20","2:40","3:20"],"correct":0,"hint":"Zwei Uhr zwanzig means twenty past two."}]}', 12),
('de', 'A1', 'listening', 'Im Restaurant bestellen', 'Ordering at a Restaurant', 'Hören Sie eine Bestellung.', 'Listen to an order.', '{"type":"listen_and_choose","instructions":"Was bestellt die Person?","exercises":[{"prompt":"Ein Schnitzel mit Pommes, bitte.","question":"Was ist das Hauptgericht?","options":["Pizza","Schnitzel","Pasta"],"correct":1,"hint":"Typisch deutsches Fleischgericht."},{"prompt":"Ich möchte ein großes Mineralwasser ohne Kohlensäure.","question":"Welches Wasser?","options":["Mit Gas","Ohne Gas"],"correct":1,"hint":"Ohne Kohlensäure (still)."},{"prompt":"Haben Sie auch vegetarische Gerichte?","question":"Was sucht die Person?","options":["Fleisch","Gemüse","Fisch"],"correct":1,"hint":"Vegetarisch (no meat)."},{"prompt":"Ich nehme einen Apfelstrudel als Nachtisch.","question":"Was ist der Nachtisch?","options":["Kuchen","Apfelstrudel","Eis"],"correct":1,"hint":"Apfel..."},{"prompt":"Die Rechnung, bitte.","question":"Was möchte die Person tun?","options":["Bestellen","Bezahlen"],"correct":1,"hint":"Rechnung (bill). fragmentation"},{"prompt":"Ich hätte gerne einen Cappuccino, bitte.","question":"Was bestellt die Person?","options":["Espresso","Cappuccino","Latte Macchiato"],"correct":1,"hint":"Ein Kaffeegetränk mit Milchschaum."},{"prompt":"Ich möchte eine Portion Spaghetti Bolognese.","question":"Was ist das Gericht?","options":["Lasagne","Spaghetti","Fettuccine"],"correct":1,"hint":"Typische italienische Pasta."},{"prompt":"Ein Stück Schwarzwälder Kirschtorte, bitte.","question":"Welches Dessert bestellt die Person?","options":["Apfelkuchen","Schwarzwälder Kirschtorte","Pudding"],"correct":1,"hint":"Mit Kirschen und Sahne."},{"prompt":"Ich hätte gerne ein vegetarisches Sandwich.","question":"Was für ein Sandwich bestellt die Person?","options":["Fleischsandwich","Thunfischsandwich","Vegetarisches Sandwich"],"correct":2,"hint":"Ohne Fleisch."},{"prompt":"Ich nehme ein Steak medium rare.","question":"Wie will die Person ihr Steak?","options":["Well done","Medium","Medium rare"],"correct":2,"hint":"Nicht ganz durchgebraten."},{"prompt":"Könnte ich bitte die Speisekarte sehen?","question":"Was möchte die Person?","options":["Die Rechnung","Die Speisekarte","Ein Getränk"],"correct":1,"hint":"Um die Gerichte auszuwählen."},{"prompt":"Ich hätte gerne ein Stück Pizza Margherita.","question":"Was bestellt die Person?","options":["Pizza Salami","Pizza Margherita","Pizza Hawaii"],"correct":1,"hint":"Mit Tomaten und Mozzarella."},{"prompt":"Ich möchte ein Glas frischen Orangensaft.","question":"Welches Getränk bestellt die Person?","options":["Äpfelsaft","Traubensaft","Orangensaft"],"correct":2,"hint":"Frisch gepresst."},{"prompt":"Ich hätte gerne eine Portion Pommes frites.","question":"Was bestellt die Person?","options":["Reis","Kartoffeln","Pommes frites"],"correct":2,"hint":"Frittierte Kartoffelstäbchen."},{"prompt":"Ein großes Bier, bitte.","question":"Was bestellt die Person?","options":["Wein","Bier","Cocktail"],"correct":1,"hint":"Ein alkoholisches Getränk aus Hopfen und Malz."},{"prompt":"Ich hätte gerne ein Stück Torte zum Kaffee.","question":"Was möchte die Person?","options":["Kekse","Torte","Schokolade"],"correct":1,"hint":"Ein süßes Gebäck."},{"prompt":"Könnte ich bitte einen Salat ohne Dressing bekommen?","question":"Was möchte die Person?","options":["Salat mit Dressing","Salat ohne Dressing","Gemüse"],"correct":1,"hint":"Ohne zusätzliche Soße."},{"prompt":"Ich möchte einen Milchshake, bitte.","question":"Was bestellt die Person?","options":["Smoothie","Milchshake","Eistee"],"correct":1,"hint":"Ein kaltes Getränk mit Eiscreme."},{"prompt":"Ich hätte gerne eine große Portion Nachos mit Käse.","question":"Was bestellt die Person?","options":["Nachos","Chips","Popcorn"],"correct":0,"hint":"Mit geschmolzenem Käse."}]}', 13),
('de', 'A1', 'listening', 'Wegbeschreibung', 'Directions', 'Hören Sie, wo Orte sind.', 'Listen to where places are.', '{"type":"listen_and_choose","instructions":"Wo ist der Ort?","exercises":[{"prompt":"Die Post ist direkt gegenüber vom Bahnhof.","question":"Wo ist die Post?","options":["Neben dem Bahnhof","Gegenüber vom Bahnhof"],"correct":1,"hint":"Gegenüber (opposite)."},{"prompt":"Gehen Sie geradeaus und dann die zweite Straße links.","question":"Welche Straße?","options":["1. links","2. links","2. rechts"],"correct":1,"hint":"Zweite... links."},{"prompt":"Die Apotheke ist zwischen der Bank und dem Supermarkt.","question":"Wo?","options":["Neben der Bank","Zwischen Bank und Supermarkt"],"correct":1,"hint":"Zwischen (between)."},{"prompt":"Biegen Sie an der Ampel rechts ab.","question":"Wohin biegen?","options":["Links","Rechts"],"correct":1,"hint":"Rechts."},{"prompt":"Der Park ist hinter dem Museum.","question":"Wo ist der Park?","options":["Vor dem Museum","Hinter dem Museum"],"correct":1,"hint":"Hinter (behind)."},{"prompt":"Die Schule ist neben der Kirche.","question":"Wo ist die Schule?","options":["Hinter der Kirche","Neben der Kirche"],"correct":1,"hint":"Neben (next to)."},{"prompt":"Der Park ist hinter dem Museum.","question":"Wo ist der Park?","options":["Vor dem Museum","Hinter dem Museum"],"correct":1,"hint":"Hinter (behind)."},{"prompt":"Das Restaurant ist am Ende der Straße.","question":"Wo ist das Restaurant?","options":["In der Mitte der Straße","Am Ende der Straße"],"correct":1,"hint":"Am Ende (at the end)."},{"prompt":"Die Bibliothek ist gegenüber dem Kino.","question":"Wo ist die Bibliothek?","options":["Neben dem Kino","Gegenüber dem Kino"],"correct":1,"hint":"Gegenüber (opposite)."},{"prompt":"Das Hotel ist auf der rechten Seite der Straße.","question":"Wo ist das Hotel?","options":["Links von der Straße","Rechts von der Straße"],"correct":1,"hint":"Rechts (right)."},{"prompt":"Die Tankstelle ist an der Ecke der Hauptstraße.","question":"Wo ist die Tankstelle?","options":["In der Mitte der Straße","An der Ecke der Hauptstraße"],"correct":1,"hint":"An der Ecke (at the corner)."},{"prompt":"Das Fitnessstudio ist über der Bäckerei.","question":"Wo ist das Fitnessstudio?","options":["Unter der Bäckerei","Über der Bäckerei"],"correct":1,"hint":"Über (above)."},{"prompt":"Der Spielplatz ist links vom Schwimmbad.","question":"Wo ist der Spielplatz?","options":["Rechts vom Schwimmbad","Links vom Schwimmbad"],"correct":1,"hint":"Links (left)."},{"prompt":"Die Wohnung ist im dritten Stock.","question":"In welchem Stockwerk ist die Wohnung?","options":["Im ersten Stock","Im dritten Stock"],"correct":1,"hint":"Dritten (third)."},{"prompt":"Die Brücke ist neben dem Fluss.","question":"Wo ist die Brücke?","options":["Über dem Fluss","Neben dem Fluss"],"correct":1,"hint":"Neben (next to)."},{"prompt":"Das Café ist in der Nähe des Marktes.","question":"Wo ist das Café?","options":["Weit vom Markt entfernt","In der Nähe des Marktes"],"correct":1,"hint":"In der Nähe (near)."},{"prompt":"Die Haltestelle ist an der Ampel.","question":"Wo ist die Haltestelle?","options":["Vor der Ampel","An der Ampel"],"correct":1,"hint":"An der Ampel (at the traffic light)."},{"prompt":"Das Stadion ist weit von der Stadt entfernt.","question":"Wo ist das Stadion?","options":["In der Stadt","Weit von der Stadt entfernt"],"correct":1,"hint":"Weit (far)."},{"prompt":"Die Metzgerei ist vor dem Supermarkt.","question":"Wo ist die Metzgerei?","options":["Hinter dem Supermarkt","Vor dem Supermarkt"],"correct":1,"hint":"Vor (in front of)."}]}', 14),
('de', 'A1', 'listening', 'Einkaufen gehen', 'Going Shopping', 'Hören Sie Lebensmittel.', 'Listen to groceries.', '{"type":"listen_and_choose","instructions":"Was steht auf der Liste?","exercises":[{"prompt":"Wir brauchen fünf Tomaten und eine Gurke.","question":"Was brauchen wir?","options":["Obst","Gemüse"],"correct":1,"hint":"Tomaten/Gurke."},{"prompt":"Kauf bitte ein Kilo Rindfleisch.","question":"Wie viel Fleisch?","options":["500g","1kg","2kg"],"correct":1,"hint":"Ein Kilo."},{"prompt":"Gibt es hier frisches Brot?","question":"Welches Produkt?","options":["Milch","Brot","Käse"],"correct":1,"hint":"Bäckerei-Produkt."},{"prompt":"Ich möchte drei Packungen Milch kaufen.","question":"Wie viele Packungen?","options":["1","2","3"],"correct":2,"hint":"Drei."},{"prompt":"Sind die Erdbeeren süß?","question":"Welches Obst?","options":["Äpfel","Erdbeeren","Bananen"],"correct":1,"hint":"Rote Sommerfrucht."},{"prompt":"Wir brauchen zwei Äpfel und drei Bananen.","question":"Was brauchen wir?","options":["Gemüse","Obst"],"correct":1,"hint":"Äpfel/Bananen."},{"prompt":"Kauf bitte drei Flaschen Wasser.","question":"Wie viel Wasser?","options":["1 Liter","3 Liter","5 Liter"],"correct":1,"hint":"Drei Flaschen."},{"prompt":"Hast du frische Eier gekauft?","question":"Welches Produkt?","options":["Milch","Eier","Käse"],"correct":1,"hint":"Frisch und wichtig."},{"prompt":"Wir benötigen eine Packung Reis.","question":"Welches Produkt?","options":["Nudeln","Reis","Brot"],"correct":1,"hint":"Es ist ein Grundnahrungsmittel."},{"prompt":"Kauf bitte zwei Paprika und eine Zucchini.","question":"Was brauchen wir?","options":["Obst","Gemüse"],"correct":1,"hint":"Paprika/Zucchini."},{"prompt":"Gibt es hier einen guten Käse?","question":"Welches Produkt?","options":["Butter","Käse","Joghurt"],"correct":1,"hint":"Ein Milchprodukt."},{"prompt":"Wir brauchen eine Flasche Olivenöl.","question":"Welches Produkt?","options":["Öl","Essig","Salz"],"correct":0,"hint":"Zum Kochen wichtig."},{"prompt":"Kauf bitte ein Kilo Kartoffeln.","question":"Wie viel Kartoffeln?","options":["250g","1kg","2kg"],"correct":1,"hint":"Ein Kilo."},{"prompt":"Hast du frische Kräuter für die Soße?","question":"Welches Produkt?","options":["Kräuter","Gewürze","Salz"],"correct":0,"hint":"Für den Geschmack."},{"prompt":"Wir brauchen ein Stück Lachs.","question":"Welches Produkt?","options":["Fleisch","Fisch"],"correct":1,"hint":"Es ist ein Meeresfrüchte."},{"prompt":"Kauf bitte zwei Packungen Zucker.","question":"Wie viel Zucker?","options":["1 Packung","2 Packungen","3 Packungen"],"correct":1,"hint":"Zucker für das Backen."},{"prompt":"Hast du frische Milch gekauft?","question":"Welches Produkt?","options":["Milch","Eier","Joghurt"],"correct":0,"hint":"Für das Frühstück."},{"prompt":"Wir benötigen eine Tüte Mehl.","question":"Welches Produkt?","options":["Mehl","Zucker","Salz"],"correct":0,"hint":"Für das Backen."},{"prompt":"Kauf bitte ein Glas Marmelade.","question":"Welches Produkt?","options":["Honig","Marmelade","Butter"],"correct":1,"hint":"Für das Brot."}]}', 15);
INSERT INTO lessons (language_code, cefr_level, skill, title, title_translation, description, description_translation, content, order_index) VALUES
('de', 'A1', 'speaking', 'Höfliche Fragen', 'Polite Questions', 'Üben Sie höfliche Fragen.', 'Practice polite questions.', '{"type":"speak_and_repeat","instructions":"Wiederholen Sie die Frage höflich.","exercises":[{"prompt":"Können Sie mir bitte helfen?","expected":"koennen sie mir bitte helfen","hint":"Can you help me?"},{"prompt":"Wie komme ich zum Bahnhof?","expected":"wie komme ich zum bahnhof","hint":"How do I get to the station?"},{"prompt":"Haben Sie einen Moment Zeit?","expected":"haben sie einen moment zeit","hint":"Do you have a moment?"},{"prompt":"Darf ich Sie etwas fragen?","expected":"darf ich sie etwas fragen","hint":"May I ask you something?"},{"prompt":"Wo ist die nächste Toilette?","expected":"wo ist die naechste toilette","hint":"Where is the toilet?"},{"prompt":"Könnten Sie mir bitte Ihren Namen sagen?","expected":"koennten sie mir bitte ihren namen sagen","hint":"Could you please tell me your name?"},{"prompt":"Darf ich Ihnen eine Frage stellen?","expected":"darf ich ihnen eine frage stellen","hint":"May I ask you a question?"},{"prompt":"Wie spät ist es?","expected":"wie spaet ist es","hint":"What time is it?"},{"prompt":"Könnten Sie das bitte wiederholen?","expected":"koennten sie das bitte wiederholen","hint":"Could you please repeat that?"},{"prompt":"Wo finde ich ein gutes Restaurant?","expected":"wo finde ich ein gutes restaurant","hint":"Where can I find a good restaurant?"},{"prompt":"Haben Sie Empfehlungen für Sehenswürdigkeiten?","expected":"haben sie empfehlungen fuer sehenswuerdigkeiten","hint":"Do you have recommendations for attractions?"},{"prompt":"Könnten Sie mir bitte den Weg beschreiben?","expected":"koennten sie mir bitte den weg beschreiben","hint":"Could you please describe the way to me?"},{"prompt":"Entschuldigung, wo ist die nächste U-Bahn-Station?","expected":"entschuldigung wo ist die naechste u-bahn-station","hint":"Excuse me, where is the nearest subway station?"},{"prompt":"Wann beginnt die nächste Vorstellung?","expected":"wann beginnt die naechste vorstellung","hint":"When does the next show start?"},{"prompt":"Könnte ich bitte die Rechnung bekommen?","expected":"koennte ich bitte die rechnung bekommen","hint":"Could I please get the bill?"},{"prompt":"Haben Sie einen Tisch für zwei Personen?","expected":"haben sie einen tisch fuer zwei personen","hint":"Do you have a table for two?"},{"prompt":"Wie lange dauert die Fahrt?","expected":"wie lange dauert die fahrt","hint":"How long does the trip take?"},{"prompt":"Könnten Sie mir bitte Ihr Zimmer zeigen?","expected":"koennten sie mir bitte ihr zimmer zeigen","hint":"Could you please show me your room?"},{"prompt":"Was empfehlen Sie als Spezialität des Hauses?","expected":"was empfehlen sie als spezialitaet des hauses","hint":"What do you recommend as the house specialty?"},{"prompt":"Darf ich hier sitzen?","expected":"darf ich hier sitzen","hint":"May I sit here?"}]}', 11),
('de', 'A1', 'speaking', 'Sich detailliert vorstellen', 'Introducing Yourself Detailed', 'Erzählen Sie mehr über sich.', 'Tell more about yourself.', '{"type":"speak_and_repeat","instructions":"Sprechen Sie den Satz klar nach.","exercises":[{"prompt":"Ich wohne seit zwei Jahren in Berlin.","expected":"ich wohne seit zwei jahren in berlin","hint":"I live since 2 years in Berlin."},{"prompt":"Mein Hobby ist das Fotografieren von Tieren.","expected":"mein hobby ist das fotografieren von tieren","hint":"My hobby is photography of animals."},{"prompt":"Ich arbeite als Lehrer in einer Schule.","expected":"ich arbeite als lehrer in einer schule","hint":"I work as a teacher."},{"prompt":"In meiner Freizeit lese ich gerne Bücher.","expected":"in meiner freizeit lese ich gerne buecher","hint":"In my free time I read."},{"prompt":"Ich spreche Deutsch, Englisch und ein bisschen Spanisch.","expected":"ich spreche deutsch englisch und ein bisschen spanisch","hint":"I speak 3 languages."},{"prompt":"Ich gehe jeden Tag joggen.","expected":"ich gehe jeden tag joggen","hint":"I go jogging every day."},{"prompt":"Mein Lieblingsessen ist Pizza.","expected":"mein lieblingsessen ist pizza","hint":"My favorite food is pizza."},{"prompt":"Wir reisen im Sommer nach Spanien.","expected":"wir reisen im sommer nach spanien","hint":"We travel to Spain in summer."},{"prompt":"Sie liest gerne Bücher über Geschichte.","expected":"sie liest gerne bücher über geschichte","hint":"She enjoys reading books about history."},{"prompt":"Er spielt jeden Samstag Fußball.","expected":"er spielt jeden samstag fußball","hint":"He plays soccer every Saturday."},{"prompt":"Ich lerne Deutsch, um in Deutschland zu studieren.","expected":"ich lerne deutsch um in deutschland zu studieren","hint":"I learn German to study in Germany."},{"prompt":"Wir haben einen Hund und eine Katze.","expected":"wir haben einen hund und eine katze","hint":"We have a dog and a cat."},{"prompt":"Mein Freund kommt aus Frankreich.","expected":"mein freund kommt aus frankreich","hint":"My friend comes from France."},{"prompt":"Ich trinke jeden Morgen Kaffee.","expected":"ich trinke jeden morgen kaffee","hint":"I drink coffee every morning."},{"prompt":"Die Schule beginnt um acht Uhr.","expected":"die schule beginnt um acht uhr","hint":"School starts at eight o''clock."},{"prompt":"Ich liebe es, neue Rezepte auszuprobieren.","expected":"ich liebe es neue rezepte auszuprobieren","hint":"I love trying new recipes."},{"prompt":"Wir gehen am Wochenende ins Kino.","expected":"wir gehen am wochenende ins kino","hint":"We go to the cinema on the weekend."},{"prompt":"Sie arbeitet in einem großen Unternehmen.","expected":"sie arbeitet in einem großen unternehmen","hint":"She works in a large company."},{"prompt":"Ich interessiere mich für Kunst und Musik.","expected":"ich interessiere mich für kunst und musik","hint":"I am interested in art and music."},{"prompt":"Mein Bruder spielt Gitarre in einer Band.","expected":"mein bruder spielt gitarre in einer band","hint":"My brother plays guitar in a band."}]}', 12),
('de', 'A1', 'speaking', 'Im Supermarkt fragen', 'Asking at the Supermarket', 'Fragen nach Produkten.', 'Asking for products.', '{"type":"speak_and_repeat","instructions":"Stellen Sie die Frage im Supermarkt.","exercises":[{"prompt":"Entschuldigung, wo finde ich das Brot?","expected":"entschuldigung wo finde ich das brot","hint":"Where is the bread?"},{"prompt":"Wie viel kostet eine Packung Eier?","expected":"wie viel kostet eine packung eier","hint":"How much for eggs?"},{"prompt":"Haben Sie heute frischen Fisch?","expected":"haben sie heute frischen fisch","hint":"Is there fresh fish?"},{"prompt":"Ist dieser Käse aus Deutschland?","expected":"ist dieser kaese aus deutschland","hint":"Is the cheese German?"},{"prompt":"Ich hätte gerne 200 Gramm Schinken.","expected":"ich haette gerne zweihundert gramm schinken","hint":"I would like 200g ham."},{"prompt":"Entschuldigung, wo finde ich die Milch?","expected":"entschuldigung wo finde ich die milch","hint":"Where is the milk?"},{"prompt":"Haben Sie auch glutenfreies Brot?","expected":"haben sie auch glutenfreies brot","hint":"Do you have gluten-free bread?"},{"prompt":"Kann ich mit Kreditkarte bezahlen?","expected":"kann ich mit kreditkarte bezahlen","hint":"Can I pay with a credit card?"},{"prompt":"Wo sind die Obst- und Gemüseabteilungen?","expected":"wo sind die obst und gemüseabteilungen","hint":"Where are the fruit and vegetable sections?"},{"prompt":"Gibt es hier eine Tiefkühlabteilung?","expected":"gibt es hier eine tiefkühlabteilung","hint":"Is there a frozen food section here?"},{"prompt":"Haben Sie auch Bio-Produkte?","expected":"haben sie auch bio produkte","hint":"Do you have organic products?"},{"prompt":"Wo kann ich die Kasse finden?","expected":"wo kann ich die kasse finden","hint":"Where can I find the checkout?"},{"prompt":"Könnte ich bitte eine Tüte bekommen?","expected":"könnte ich bitte eine tüte bekommen","hint":"Could I please get a bag?"},{"prompt":"Wie viel kostet das Obst?","expected":"wie viel kostet das obst","hint":"How much does the fruit cost?"},{"prompt":"Haben Sie Rabatte auf Getränke?","expected":"haben sie rabatte auf getränke","hint":"Do you have discounts on drinks?"},{"prompt":"Wo sind die Süßigkeiten?","expected":"wo sind die süßigkeiten","hint":"Where are the candies?"},{"prompt":"Gibt es hier einen Kundenservice?","expected":"gibt es hier einen kundenservice","hint":"Is there a customer service here?"},{"prompt":"Haben Sie frische Kräuter?","expected":"haben sie frische kräuter","hint":"Do you have fresh herbs?"},{"prompt":"Wo kann ich die Toiletten finden?","expected":"wo kann ich die toiletten finden","hint":"Where can I find the restrooms?"},{"prompt":"Könnte ich bitte eine Quittung bekommen?","expected":"könnte ich bitte eine quittung bekommen","hint":"Could I please get a receipt?"}]}', 13),
('de', 'A1', 'speaking', 'Tagesablauf beschreiben', 'Describing Daily Routine', 'Einfache Aktionen am Tag.', 'Simple daily actions.', '{"type":"speak_and_repeat","instructions":"Sprechen Sie über Ihren Tag.","exercises":[{"prompt":"Ich stehe jeden Morgen um sieben Uhr auf.","expected":"ich stehe jeden morgen um sieben uhr auf","hint":"I get up at 7."},{"prompt":"Nach dem Frühstück gehe ich zur Arbeit.","expected":"nach dem fruehstueck gehe ich zur arbeit","hint":"After breakfast I go to work."},{"prompt":"Am Abend koche ich meistens mit meiner Familie.","expected":"am abend koche ich meistens mit meiner familie","hint":"In the evening I cook."},{"prompt":"Ich gehe um elf Uhr schlafen.","expected":"ich gehe um elf uhr schlafen","hint":"I go to sleep at 11."},{"prompt":"Am Wochenende schlafe ich gerne lange.","expected":"am wochenende schlafe ich gerne lange","hint":"Long sleep on weekend."},{"prompt":"Ich mache morgens Sport im Park.","expected":"ich mache morgens sport im park","hint":"I exercise in the park in the morning."},{"prompt":"Mittags esse ich oft mit Freunden.","expected":"mittags esse ich oft mit freunden","hint":"I often eat with friends at noon."},{"prompt":"Nach der Arbeit gehe ich ins Kino.","expected":"nach der arbeit gehe ich ins kino","hint":"After work, I go to the cinema."},{"prompt":"Ich lese jeden Abend ein Buch.","expected":"ich lese jeden abend ein buch","hint":"I read a book every evening."},{"prompt":"Am Wochenende mache ich einen Ausflug.","expected":"am wochenende mache ich einen ausflug","hint":"On the weekend, I go on a trip."},{"prompt":"Ich telefoniere oft mit meiner Familie.","expected":"ich telefoniere oft mit meiner familie","hint":"I often talk on the phone with my family."},{"prompt":"Ich esse Frühstück um acht Uhr.","expected":"ich esse fruehstueck um acht uhr","hint":"I have breakfast at 8."},{"prompt":"Ich arbeite von neun bis fünf.","expected":"ich arbeite von neun bis fuenz","hint":"I work from 9 to 5."},{"prompt":"Abends sehe ich oft fern.","expected":"abends sehe ich oft fern","hint":"In the evening, I often watch TV."},{"prompt":"Ich gehe jeden Sonntag zur Kirche.","expected":"ich gehe jeden sonntag zur kirche","hint":"I go to church every Sunday."},{"prompt":"Ich mache meine Hausaufgaben nach der Schule.","expected":"ich mache meine hausaufgaben nach der schule","hint":"I do my homework after school."},{"prompt":"Ich trinke jeden Morgen Kaffee.","expected":"ich trinke jeden morgen kaffee","hint":"I drink coffee every morning."},{"prompt":"Ich besuche meine Freunde am Freitag.","expected":"ich besuche meine freunde am freitag","hint":"I visit my friends on Friday."},{"prompt":"Nach dem Abendessen gehe ich spazieren.","expected":"nach dem abendessen gehe ich spazieren","hint":"After dinner, I go for a walk."},{"prompt":"Ich mache jeden Tag Yoga.","expected":"ich mache jeden tag yoga","hint":"I do yoga every day."},{"prompt":"Ich schreibe in mein Tagebuch vor dem Schlafen.","expected":"ich schreibe in mein tagebuch vor dem schlafen","hint":"I write in my diary before sleeping."}]}', 14),
('de', 'A1', 'speaking', 'Arztbesuch', 'Visit to the Doctor', 'Symptome nennen.', 'Naming symptoms.', '{"type":"speak_and_repeat","instructions":"Nennen Sie Ihr Symptom.","exercises":[{"prompt":"Ich habe schreckliche Kopfschmerzen.","expected":"ich habe schreckliche kopfschmerzen","hint":"Bad headache."},{"prompt":"Mein Hals tut beim Schlucken weh.","expected":"mein hals tut beim schlucken weh","hint":"Throat hurts."},{"prompt":"Ich habe seit drei Tagen Fieber.","expected":"ich habe seit drei tagen fieber","hint":"Fever since 3 days."},{"prompt":"Kann ich bitte ein Rezept bekommen?","expected":"kann ich bitte ein rezept bekommen","hint":"Can I have a prescription?"},{"prompt":"Ich fühle mich heute sehr schwach.","expected":"ich fuehle mich heute sehr schwach","hint":"I feel very weak."},{"prompt":"Ich fühle mich sehr müde.","expected":"ich fühle mich sehr müde","hint":"Feeling very tired."},{"prompt":"Mein Bauch tut weh.","expected":"mein bauch tut weh","hint":"Stomach hurts."},{"prompt":"Ich habe Husten und Schnupfen.","expected":"ich habe husten und schnupfen","hint":"Cough and cold."},{"prompt":"Ich habe Allergien.","expected":"ich habe allergien","hint":"Allergies."},{"prompt":"Meine Muskeln sind verspannt.","expected":"meine muskeln sind verspannt","hint":"Muscles are tense."},{"prompt":"Ich fühle mich schwindelig.","expected":"ich fühle mich schwindelig","hint":"Feeling dizzy."},{"prompt":"Ich habe einen trockenen Mund.","expected":"ich habe einen trockenen mund","hint":"Dry mouth."},{"prompt":"Mein Rücken schmerzt.","expected":"mein rücken schmerzt","hint":"Back pain."},{"prompt":"Ich habe Atemnot.","expected":"ich habe atemnot","hint":"Shortness of breath."},{"prompt":"Ich fühle mich übel.","expected":"ich fühle mich übel","hint":"Feeling nauseous."},{"prompt":"Ich habe Gelenkschmerzen.","expected":"ich habe gelenkschmerzen","hint":"Joint pain."},{"prompt":"Ich habe Durchfall.","expected":"ich habe durchfall","hint":"Diarrhea."},{"prompt":"Ich habe Fieber und Schüttelfrost.","expected":"ich habe fieber und schüttelfrost","hint":"Fever and chills."},{"prompt":"Ich habe eine Erkältung.","expected":"ich habe eine erkältung","hint":"Cold."},{"prompt":"Ich habe Schmerzen in der Brust.","expected":"ich habe schmerzen in der brust","hint":"Chest pain."}]}', 15);
