('de', 'A1', 'reading', 'Öffnungszeiten lesen', 'Reading Opening Hours', 'Verstehen Sie, wann Läden offen sind.', 'Understand when shops are open.', '{"type":"read_and_choose","instructions":"Lesen Sie die Zeiten und antworten Sie.","exercises":[{"sentence":"Die Bäckerei ist von Montag bis Freitag von 6 bis 18 Uhr geöffnet.","question":"Wann öffnet die Bäckerei?","options":["6 Uhr","8 Uhr","18 Uhr"],"correct":0,"explanation":"Öffnet um 6 Uhr."},{"sentence":"Am Samstag schließt der Laden schon um 13 Uhr.","question":"Schließzeit am Samstag?","options":["13 Uhr","15 Uhr","18 Uhr"],"correct":0,"explanation":"Schließt um 13 Uhr."},{"sentence":"Sonntags bleibt die Bäckerei geschlossen.","question":"Kunde kommt am Sonntag:","options":["Offen","Zu"],"correct":1,"explanation":"Geschlossen (closed)."},{"sentence":"Mittagspause ist täglich von 12:30 bis 13:30 Uhr.","question":"Wie lange ist Pause?","options":["30 Minuten","60 Minuten"],"correct":1,"explanation":"Eine Stunde (12:30-13:30)."},{"sentence":"Feiertags gelten besondere Zeiten.","question":"Gleiche Zeiten an Feiertagen?","options":["Ja","Nein"],"correct":1,"explanation":"Besondere Zeiten (special times)."},{"sentence":"Die Bibliothek hat von Dienstag bis Donnerstag von 10 bis 19 Uhr geöffnet.","question":"Wann schließt die Bibliothek am Donnerstag?","options":["19 Uhr","17 Uhr","20 Uhr"],"correct":0,"explanation":"Schließt um 19 Uhr."},{"sentence":"Das Restaurant öffnet täglich um 11 Uhr und schließt um 22 Uhr.","question":"Was ist die Öffnungszeit des Restaurants?","options":["11 Uhr","10 Uhr","12 Uhr"],"correct":0,"explanation":"Öffnet um 11 Uhr."},{"sentence":"Der Supermarkt hat am Sonntag von 9 bis 14 Uhr geöffnet.","question":"Wann schließt der Supermarkt am Sonntag?","options":["14 Uhr","16 Uhr","12 Uhr"],"correct":0,"explanation":"Schließt um 14 Uhr."},{"sentence":"Die Post ist von Montag bis Freitag von 8 bis 18 Uhr geöffnet.","question":"Wann öffnet die Post?","options":["8 Uhr","9 Uhr","7 Uhr"],"correct":0,"explanation":"Öffnet um 8 Uhr."},{"sentence":"Das Kino hat am Freitag eine Vorstellung um 20 Uhr.","question":"Wann beginnt die Vorstellung am Freitag?","options":["20 Uhr","19 Uhr","21 Uhr"],"correct":0,"explanation":"Beginn um 20 Uhr."},{"sentence":"Die Schwimmhalle öffnet Montag bis Samstag von 6 bis 22 Uhr.","question":"Schließt die Schwimmhalle am Montag?","options":["22 Uhr","20 Uhr","21 Uhr"],"correct":0,"explanation":"Schließt um 22 Uhr."},{"sentence":"Am Mittwoch bleibt der Zoo geschlossen.","question":"Kunde will am Mittwoch gehen:","options":["Offen","Zu"],"correct":1,"explanation":"Geschlossen (closed)."},{"sentence":"Das Fitnessstudio hat von 5 bis 23 Uhr geöffnet.","question":"Wann ist das Fitnessstudio zu?","options":["23 Uhr","22 Uhr","21 Uhr"],"correct":0,"explanation":"Schließt um 23 Uhr."},{"sentence":"Die Apotheke hat am Samstag von 9 bis 17 Uhr geöffnet.","question":"Schließt die Apotheke am Samstag?","options":["17 Uhr","18 Uhr","16 Uhr"],"correct":0,"explanation":"Schließt um 17 Uhr."},{"sentence":"Das Museum öffnet von Donnerstag bis Sonntag von 10 bis 18 Uhr.","question":"Wann öffnet das Museum am Sonntag?","options":["10 Uhr","11 Uhr","9 Uhr"],"correct":0,"explanation":"Öffnet um 10 Uhr."},{"sentence":"Der Wochenmarkt findet jeden Samstag von 8 bis 13 Uhr statt.","question":"Wann endet der Wochenmarkt?","options":["13 Uhr","12 Uhr","14 Uhr"],"correct":0,"explanation":"Endet um 13 Uhr."},{"sentence":"Das Café hat von Montag bis Freitag von 7 bis 19 Uhr geöffnet.","question":"Wann schließt das Café am Freitag?","options":["19 Uhr","18 Uhr","20 Uhr"],"correct":0,"explanation":"Schließt um 19 Uhr."},{"sentence":"Die Kindertagesstätte hat von 7 bis 17 Uhr geöffnet.","question":"Wann ist die Kindertagesstätte zu?","options":["17 Uhr","16 Uhr","15 Uhr"],"correct":0,"explanation":"Schließt um 17 Uhr."},{"sentence":"Die Bank hat am Samstag von 9 bis 12 Uhr geöffnet.","question":"Wann schließt die Bank am Samstag?","options":["12 Uhr","11 Uhr","13 Uhr"],"correct":0,"explanation":"Schließt um 12 Uhr."},{"sentence":"Die Schule beginnt um 8 Uhr und endet um 15 Uhr.","question":"Wann endet die Schule?","options":["15 Uhr","14 Uhr","16 Uhr"],"correct":0,"explanation":"Endet um 15 Uhr."}]}', 11),
('de', 'A1', 'reading', 'Die Einkaufsliste', 'The Shopping List', 'Was müssen wir kaufen?', 'What do we need to buy?', '{"type":"read_and_choose","instructions":"Finden Sie das Produkt.","exercises":[{"sentence":"Wir brauchen Äpfel für den Kuchen und Bananen für das Müsli.","question":"Wofür sind die Äpfel?","options":["Müsli","Kuchen"],"correct":1,"explanation":"Äpfel für den Kuchen."},{"sentence":"Bitte kauf auch eine Packung Butter und zwei Liter Milch.","question":"Wie viel Milch?","options":["1 Liter","2 Liter","3 Liter"],"correct":1,"explanation":"Zwei Liter."},{"sentence":"Der Käse muss aus Frankreich sein, nicht aus Holland.","question":"Herkunft des Käses?","options":["Holland","Frankreich"],"correct":1,"explanation":"Aus Frankreich."},{"sentence":"Wir haben noch genug Brot, also kauf kein neues.","question":"Brot kaufen?","options":["Brot kaufen","Kein Brot kaufen"],"correct":1,"explanation":"Kauf kein neues."},{"sentence":"Eier sind im Angebot für 1,99 Euro.","question":"Preis für Eier?","options":["1,99 Euro","2,99 Euro"],"correct":0,"explanation":"1,99 Euro."},{"sentence":"Ich hätte gerne einen Salat mit Tomaten und Gurken.","question":"Welche Zutaten sind im Salat?","options":["Tomaten","Karotten"],"correct":0,"explanation":"Tomaten und Gurken sind im Salat."},{"sentence":"Wir brauchen zwei Hähnchenbrustfilets und einen Beutel Reis.","question":"Wie viele Hähnchenbrustfilets?","options":["1","2"],"correct":1,"explanation":"Zwei Hähnchenbrustfilets."},{"sentence":"Die Karotten sollen frisch und knackig sein, bitte.","question":"Wie sollten die Karotten sein?","options":["Alt","Frisch"],"correct":1,"explanation":"Sie sollen frisch und knackig sein."},{"sentence":"Kauf bitte ein Glas Marmelade und eine Packung Kekse.","question":"Was soll gekauft werden?","options":["Marmelade","Honig"],"correct":0,"explanation":"Ein Glas Marmelade."},{"sentence":"Wir benötigen einen Liter Orangensaft für das Frühstück.","question":"Wie viel Orangensaft wird benötigt?","options":["0,5 Liter","1 Liter"],"correct":1,"explanation":"Einen Liter Orangensaft."},{"sentence":"Die Tomaten sollten reif sein, nicht grün.","question":"Wie sollten die Tomaten sein?","options":["Reif","Grün"],"correct":0,"explanation":"Die Tomaten sollten reif sein."},{"sentence":"Bitte bring eine Flasche Wasser und eine Packung Chips mit.","question":"Was soll mitgebracht werden?","options":["Wasser","Bier"],"correct":0,"explanation":"Eine Flasche Wasser."},{"sentence":"Wir brauchen frische Kräuter für die Suppe.","question":"Was wird für die Suppe benötigt?","options":["Kräuter","Gemüse"],"correct":0,"explanation":"Frische Kräuter."},{"sentence":"Ich möchte einen großen Kuchen und einige Muffins backen.","question":"Was wird gebacken?","options":["Kekse","Kuchen"],"correct":1,"explanation":"Einen großen Kuchen."},{"sentence":"Wir brauchen frischen Fisch und etwas Gemüse.","question":"Was ist ein weiteres benötigtes Produkt?","options":["Reis","Gemüse"],"correct":1,"explanation":"Etwas Gemüse."},{"sentence":"Die Äpfel sollten rot und süß sein.","question":"Wie sollten die Äpfel sein?","options":["Sauer","Rot und süß"],"correct":1,"explanation":"Rot und süß."},{"sentence":"Kauf bitte ein Kilo Kartoffeln und einen Bund Petersilie.","question":"Wie viel Kartoffeln?","options":["500 Gramm","1 Kilo"],"correct":1,"explanation":"Ein Kilo Kartoffeln."},{"sentence":"Wir brauchen frisches Brot für das Abendessen.","question":"Was wird für das Abendessen benötigt?","options":["Brot","Brötchen"],"correct":0,"explanation":"Frisches Brot."},{"sentence":"Ich hätte gern einen Becher Joghurt und ein Stück Obst.","question":"Was ist ein weiteres Produkt?","options":["Joghurt","Käse"],"correct":0,"explanation":"Ein Becher Joghurt."},{"sentence":"Bitte bring eine Packung Spaghetti und eine Dose Tomatensauce mit.","question":"Was wird benötigt?","options":["Spaghetti","Reis"],"correct":0,"explanation":"Eine Packung Spaghetti."}]}', 12),
('de', 'A1', 'reading', 'Wohnungsanzeige', 'Apartment Ad', 'Informationen über eine Wohnung.', 'Information about an apartment.', '{"type":"read_and_choose","instructions":"Verstehen Sie die Anzeige.","exercises":[{"sentence":"Schöne 2-Zimmer-Wohnung im Zentrum zu vermieten.","question":"Wie viele Zimmer?","options":["1","2","3"],"correct":1,"explanation":"2-Zimmer-Wohnung."},{"sentence":"Die Miete beträgt 600 Euro warm pro Monat.","question":"Wie hoch ist die Miete?","options":["500 Euro","600 Euro"],"correct":1,"explanation":"600 Euro."},{"sentence":"Die Wohnung hat einen Balkon und eine kleine Küche.","question":"Gibt es einen Balkon?","options":["Ja","Nein"],"correct":0,"explanation":"Hat einen Balkon."},{"sentence":"Haustiere sind leider nicht erlaubt.","question":"Hund mitbringen?","options":["Erlaubt","Nicht erlaubt"],"correct":1,"explanation":"Nicht erlaubt (not allowed)."},{"sentence":"Besichtigung ist am Freitag um 16 Uhr.","question":"Wann ist der Termin?","options":["Donnerstag","Freitag"],"correct":1,"explanation":"Am Freitag."},{"sentence":"Gemütliche 3-Zimmer-Wohnung in ruhiger Lage zu verkaufen.","question":"Wie viele Zimmer hat die Wohnung?","options":["2","3"],"correct":1,"explanation":"3-Zimmer-Wohnung."},{"sentence":"Die Wohnung ist 80 Quadratmeter groß.","question":"Wie groß ist die Wohnung?","options":["70 Quadratmeter","80 Quadratmeter"],"correct":1,"explanation":"80 Quadratmeter."},{"sentence":"Die Miete beträgt 750 Euro kalt pro Monat.","question":"Ist die Miete warm oder kalt?","options":["Warm","Kalt"],"correct":1,"explanation":"750 Euro kalt."},{"sentence":"Die Wohnung hat einen Parkplatz und einen Garten.","question":"Gibt es einen Garten?","options":["Ja","Nein"],"correct":0,"explanation":"Hat einen Garten."},{"sentence":"Die Wohnung befindet sich in der Nähe des Stadtzentrums.","question":"Liegt die Wohnung im Stadtzentrum?","options":["Ja","Nein"],"correct":1,"explanation":"In der Nähe, aber nicht im Zentrum."},{"sentence":"Die Wohnung hat eine moderne Ausstattung und ist frisch renoviert.","question":"Ist die Wohnung renoviert?","options":["Ja","Nein"],"correct":0,"explanation":"Frisch renoviert."},{"sentence":"Die Wohnung ist ideal für Paare oder kleine Familien.","question":"Für wen ist die Wohnung ideal?","options":["Alleinstehende","Paare oder kleine Familien"],"correct":1,"explanation":"Ideal für Paare oder kleine Familien."},{"sentence":"Die Wohnung hat eine schöne Aussicht auf die Berge.","question":"Gibt es eine Aussicht?","options":["Ja","Nein"],"correct":0,"explanation":"Schöne Aussicht auf die Berge."},{"sentence":"Die Nebenkosten betragen 150 Euro pro Monat.","question":"Wie hoch sind die Nebenkosten?","options":["100 Euro","150 Euro"],"correct":1,"explanation":"150 Euro Nebenkosten."},{"sentence":"Die Wohnung ist ab sofort verfügbar.","question":"Wann ist die Wohnung verfügbar?","options":["In einem Monat","Ab sofort"],"correct":1,"explanation":"Ab sofort verfügbar."},{"sentence":"Die Wohnung hat eine gute Anbindung an öffentliche Verkehrsmittel.","question":"Gibt es eine gute Anbindung?","options":["Ja","Nein"],"correct":0,"explanation":"Gute Anbindung an öffentliche Verkehrsmittel."},{"sentence":"Die Wohnung ist mit einer Fußbodenheizung ausgestattet.","question":"Hat die Wohnung eine Fußbodenheizung?","options":["Ja","Nein"],"correct":0,"explanation":"Ist mit Fußbodenheizung ausgestattet."},{"sentence":"Die Wohnung hat einen Aufzug im Gebäude.","question":"Gibt es einen Aufzug?","options":["Ja","Nein"],"correct":0,"explanation":"Hat einen Aufzug."},{"sentence":"Die Wohnung liegt in einem familienfreundlichen Viertel.","question":"Ist das Viertel familienfreundlich?","options":["Ja","Nein"],"correct":0,"explanation":"Familienfreundliches Viertel."},{"sentence":"Die Wohnung hat eine Einbauküche und einen Abstellraum.","question":"Gibt es eine Einbauküche?","options":["Ja","Nein"],"correct":0,"explanation":"Hat eine Einbauküche."}]}', 13),
('de', 'A1', 'reading', 'Eine E-Mail von Paul', 'An Email from Paul', 'Paul schreibt über seinen Urlaub.', 'Paul writes about his vacation.', '{"type":"read_and_choose","instructions":"Lesen Sie die E-Mail.","exercises":[{"sentence":"Hallo Maria, ich bin jetzt in den Bergen in Bayern.","question":"Wo ist Paul?","options":["Am Meer","In den Bergen"],"correct":1,"explanation":"In den Bergen."},{"sentence":"Das Wetter ist toll, die Sonne scheint den ganzen Tag.","question":"Wie ist das Wetter?","options":["Regnerisch","Sonnig"],"correct":1,"explanation":"Sonne scheint."},{"sentence":"Ich wandere viel und mache viele Fotos von der Natur.","question":"Was macht Paul?","options":["Skifahren","Wandern"],"correct":1,"explanation":"Ich wandere viel."},{"sentence":"Das Essen in der Hütte ist sehr lecker und günstig.","question":"Ist das Essen teuer?","options":["Ja","Nein"],"correct":1,"explanation":"Günstig (cheap)."},{"sentence":"Ich komme am Sonntagabend zurück. Bis bald, Paul.","question":"Wann kommt er zurück?","options":["Samstag","Sonntag"],"correct":1,"explanation":"Sonntagabend."},{"sentence":"Ich habe gestern einen schönen Tag am See verbracht.","question":"Was hat die Person gestern gemacht?","options":["Einen Film gesehen","Am See verbracht"],"correct":1,"explanation":"Einen schönen Tag am See verbracht."},{"sentence":"Die Blumen blühen und die Vögel singen.","question":"Was ist im Frühling zu hören?","options":["Vögel singen","Schnee fallen"],"correct":0,"explanation":"Die Vögel singen."},{"sentence":"Ich habe ein neues Buch über die Alpen gekauft.","question":"Was hat die Person gekauft?","options":["Ein neues Buch","Ein neues Auto"],"correct":0,"explanation":"Ein neues Buch über die Alpen."},{"sentence":"Wir planen ein Picknick im Park für das Wochenende.","question":"Was planen die Leute?","options":["Ein Picknick","Eine Reise"],"correct":0,"explanation":"Ein Picknick im Park."},{"sentence":"Die Kinder spielen Fußball im Garten.","question":"Was spielen die Kinder?","options":["Tennis","Fußball"],"correct":1,"explanation":"Die Kinder spielen Fußball."},{"sentence":"Ich koche heute Abend Pasta mit Tomatensoße.","question":"Was koche ich heute Abend?","options":["Suppe","Pasta"],"correct":1,"explanation":"Pasta mit Tomatensoße."},{"sentence":"Wir gehen morgen ins Kino, um einen neuen Film zu sehen.","question":"Wohin gehen wir morgen?","options":["Ins Kino","Ins Restaurant"],"correct":0,"explanation":"Wir gehen ins Kino."},{"sentence":"Ich habe am Wochenende meine Freunde besucht.","question":"Was habe ich am Wochenende gemacht?","options":["Meine Freunde besucht","Gekauft"],"correct":0,"explanation":"Ich habe meine Freunde besucht."},{"sentence":"Die Katze schläft auf dem Sofa.","question":"Wo schläft die Katze?","options":["Auf dem Stuhl","Auf dem Sofa"],"correct":1,"explanation":"Die Katze schläft auf dem Sofa."},{"sentence":"Ich höre gerne Musik, während ich arbeite.","question":"Was mache ich, während ich arbeite?","options":["Musik hören","Fernsehen"],"correct":0,"explanation":"Ich höre Musik."},{"sentence":"Wir haben ein neues Fahrrad für die Tour gekauft.","question":"Was haben wir gekauft?","options":["Ein neues Auto","Ein neues Fahrrad"],"correct":1,"explanation":"Ein neues Fahrrad für die Tour."},{"sentence":"Der Hund bellt, weil er einen Briefträger sieht.","question":"Warum bellt der Hund?","options":["Weil er Hunger hat","Weil er einen Briefträger sieht"],"correct":1,"explanation":"Weil er einen Briefträger sieht."},{"sentence":"Ich trinke jeden Morgen einen Kaffee.","question":"Was trinke ich jeden Morgen?","options":["Tee","Kaffee"],"correct":1,"explanation":"Ich trinke Kaffee."},{"sentence":"Die Schule beginnt um acht Uhr.","question":"Wann beginnt die Schule?","options":["Um neun Uhr","Um acht Uhr"],"correct":1,"explanation":"Die Schule beginnt um acht Uhr."},{"sentence":"Ich lese jeden Abend ein Kapitel vor dem Schlafengehen.","question":"Was mache ich jeden Abend?","options":["Fernsehen","Ein Kapitel lesen"],"correct":1,"explanation":"Ich lese ein Kapitel vor dem Schlafengehen."}]}', 14),
('de', 'A1', 'reading', 'Der Steckbrief', 'The Profile', 'Informationen über eine Person.', 'Information about a person.', '{"type":"read_and_choose","instructions":"Finden Sie die Details.","exercises":[{"sentence":"Name: Thomas Müller, Alter: 28 Jahre, Beruf: Informatiker.","question":"Wie alt ist Thomas?","options":["18","28","38"],"correct":1,"explanation":"28 Jahre."},{"sentence":"Wohnort: München, Familienstand: ledig.","question":"Wo wohnt er?","options":["Berlin","München","Hamburg"],"correct":1,"explanation":"Wohnort: München."},{"sentence":"Hobbys: Fußball spielen und Reisen.","question":"Spielt er Fußball?","options":["Ja","Nein"],"correct":0,"explanation":"Hobby ist Fußball."},{"sentence":"Sprachen: Deutsch und Französisch.","question":"Spricht er Englisch?","options":["Wird nicht erwähnt","Ja"],"correct":0,"explanation":"Nur Deutsch und Französisch genannt."},{"sentence":"Er sucht eine WG in der Stadtmitte.","question":"Was sucht er?","options":["Haus","WG"],"correct":1,"explanation":"Sucht eine WG."},{"sentence":"Name: Anna Schmidt, Alter: 34 Jahre, Beruf: Lehrerin.","question":"Was ist Annas Beruf?","options":["Ärztin","Lehrerin","Ingenieurin"],"correct":1,"explanation":"Beruf: Lehrerin."},{"sentence":"Wohnort: Frankfurt, Familienstand: verheiratet.","question":"Ist sie verheiratet?","options":["Ja","Nein"],"correct":0,"explanation":"Familienstand: verheiratet."},{"sentence":"Hobbys: Malen und Tanzen.","question":"Mag sie Tanzen?","options":["Ja","Nein"],"correct":0,"explanation":"Hobby ist Tanzen."},{"sentence":"Name: Markus Bauer, Alter: 45 Jahre, Beruf: Architekt.","question":"Wie alt ist Markus?","options":["40","45","50"],"correct":1,"explanation":"45 Jahre."},{"sentence":"Wohnort: Stuttgart, Familienstand: geschieden.","question":"Wo wohnt Markus?","options":["Stuttgart","Düsseldorf","Köln"],"correct":0,"explanation":"Wohnort: Stuttgart."},{"sentence":"Hobbys: Schwimmen und Lesen.","question":"Liest er gerne?","options":["Ja","Nein"],"correct":0,"explanation":"Hobby ist Lesen."},{"sentence":"Name: Julia Weiss, Alter: 22 Jahre, Beruf: Studentin.","question":"Was studiert Julia?","options":["Medizin","Ingenieurwissenschaften","Das wird nicht erwähnt"],"correct":2,"explanation":"Der Studiengang wird nicht erwähnt."},{"sentence":"Wohnort: Hamburg, Familienstand: in einer Beziehung.","question":"Ist sie in einer Beziehung?","options":["Ja","Nein"],"correct":0,"explanation":"Familienstand: in einer Beziehung."},{"sentence":"Hobbys: Gitarre spielen und Fotografie.","question":"Spielt sie ein Instrument?","options":["Ja","Nein"],"correct":0,"explanation":"Hobby ist Gitarre spielen."},{"sentence":"Name: Stefan Klein, Alter: 30 Jahre, Beruf: Journalist.","question":"Wie alt ist Stefan?","options":["25","30","35"],"correct":1,"explanation":"30 Jahre."},{"sentence":"Wohnort: Berlin, Familienstand: ledig.","question":"Wo lebt Stefan?","options":["Berlin","München","Hamburg"],"correct":0,"explanation":"Wohnort: Berlin."},{"sentence":"Hobbys: Kochen und Reisen.","question":"Kocht er gerne?","options":["Ja","Nein"],"correct":0,"explanation":"Hobby ist Kochen."},{"sentence":"Name: Laura Fischer, Alter: 27 Jahre, Beruf: Designerin.","question":"Was macht Laura beruflich?","options":["Ärztin","Designerin","Lehrerin"],"correct":1,"explanation":"Beruf: Designerin."},{"sentence":"Wohnort: Köln, Familienstand: verheiratet.","question":"Ist sie verheiratet?","options":["Ja","Nein"],"correct":0,"explanation":"Familienstand: verheiratet."},{"sentence":"Hobbys: Yoga und Reisen.","question":"Macht sie Yoga?","options":["Ja","Nein"],"correct":0,"explanation":"Hobby ist Yoga."}]}', 15);
