('de', 'A1', 'writing', 'Artikel üben (Akkusativ)', 'Practicing Articles (Accusative)', 'Wählen Sie den richtigen Artikel.', 'Choose the correct article.', '{"type":"type_word","instructions":"Tippen Sie den Artikel (den/die/das).","exercises":[{"prompt":"Ich habe [the] Hund. (maskulin)","expected":"den","hint":"Akkusativ maskulin."},{"prompt":"Ich kaufe [the] Tasche. (feminin)","expected":"die","hint":"Akkusativ feminin."},{"prompt":"Wir essen [the] Brot. (neutral)","expected":"das","hint":"Akkusativ neutral."},{"prompt":"Sie sucht [the] Schlüssel. (maskulin)","expected":"den","hint":"Akkusativ maskulin."},{"prompt":"Er liest [the] Buch. (neutral)","expected":"das","hint":"Akkusativ neutral."},{"prompt":"Ich sehe [the] Lehrer. (maskulin)","expected":"den","hint":"Akkusativ maskulin."},{"prompt":"Er liebt [the] Katze. (feminin)","expected":"die","hint":"Akkusativ feminin."},{"prompt":"Wir trinken [the] Wein. (neutral)","expected":"den","hint":"Akkusativ maskulin."},{"prompt":"Sie kauft [the] Lampe. (feminin)","expected":"die","hint":"Akkusativ feminin."},{"prompt":"Ich finde [the] Stuhl. (maskulin)","expected":"den","hint":"Akkusativ maskulin."},{"prompt":"Du nimmst [the] Apfel. (maskulin)","expected":"den","hint":"Akkusativ maskulin."},{"prompt":"Wir essen [the] Pizza. (feminin)","expected":"die","hint":"Akkusativ feminin."},{"prompt":"Er sieht [the] Flugzeug. (neutral)","expected":"das","hint":"Akkusativ neutral."},{"prompt":"Ich habe [the] Schlüssel. (maskulin)","expected":"den","hint":"Akkusativ maskulin."},{"prompt":"Sie mag [the] Blumen. (feminin, plural)","expected":"die","hint":"Akkusativ feminin, plural."},{"prompt":"Wir kaufen [the] Fernseher. (maskulin)","expected":"den","hint":"Akkusativ maskulin."},{"prompt":"Du brauchst [the] Wasser. (neutral)","expected":"das","hint":"Akkusativ neutral."},{"prompt":"Ich sehe [the] Freundin. (feminin)","expected":"die","hint":"Akkusativ feminin."},{"prompt":"Er findet [the] Buch. (neutral)","expected":"das","hint":"Akkusativ neutral."},{"prompt":"Wir essen [the] Erdbeeren. (feminin, plural)","expected":"die","hint":"Akkusativ feminin, plural."}]}', 11),
('de', 'A1', 'writing', 'Pluralformen', 'Plural Forms', 'Schreiben Sie den Plural.', 'Write the plural.', '{"type":"type_word","instructions":"Schreiben Sie das Wort im Plural.","exercises":[{"prompt":"Ein Apfel, zwei...","expected":"Aepfel","hint":"Umlaut + e."},{"prompt":"Ein Kind, zwei...","expected":"Kinder","hint":"Endung -er."},{"prompt":"Ein Buch, zwei...","expected":"Buecher","hint":"Umlaut + er."},{"prompt":"Eine Frau, zwei...","expected":"Frauen","hint":"Endung -en."},{"prompt":"Ein Tag, zwei...","expected":"Tage","hint":"Endung -e."},{"prompt":"Ein Tisch, zwei...","expected":"Tische","hint":"Umlaut + e."},{"prompt":"Eine Blume, zwei...","expected":"Blumen","hint":"Endung -n."},{"prompt":"Ein Hund, zwei...","expected":"Hunde","hint":"Endung -e."},{"prompt":"Ein Stuhl, zwei...","expected":"Stuehle","hint":"Umlaut + e."},{"prompt":"Ein Lehrer, zwei...","expected":"Lehrer","hint":"Endung -er bleibt gleich."},{"prompt":"Ein Auto, zwei...","expected":"Autos","hint":"Endung -s."},{"prompt":"Eine Katze, zwei...","expected":"Katzen","hint":"Endung -n."},{"prompt":"Ein Fisch, zwei...","expected":"Fische","hint":"Endung -e."},{"prompt":"Ein Schuh, zwei...","expected":"Schuhe","hint":"Umlaut + e."},{"prompt":"Ein Vogel, zwei...","expected":"Voegel","hint":"Umlaut + e."},{"prompt":"Ein Lehrer, zwei...","expected":"Lehrer","hint":"Endung -er bleibt gleich."},{"prompt":"Ein Haus, zwei...","expected":"Haeuser","hint":"Umlaut + er."},{"prompt":"Ein Fenster, zwei...","expected":"Fenster","hint":"Bleibt gleich."},{"prompt":"Ein Freund, zwei...","expected":"Freunde","hint":"Endung -e."},{"prompt":"Eine Stadt, zwei...","expected":"Staedte","hint":"Umlaut + e."}]}', 12),
('de', 'A1', 'writing', 'Verben konjugieren', 'Conjugating Verbs', 'Tippen Sie die richtige Form.', 'Type the correct form.', '{"type":"type_word","instructions":"Konjugieren Sie das Verb.","exercises":[{"prompt":"Ich [to come] aus Deutschland.","expected":"komme","hint":"ich-Endung -e."},{"prompt":"Du [to speak] sehr gut Deutsch.","expected":"sprichst","hint":"Vokalwechsel e -> i."},{"prompt":"Er [to live] in Köln.","expected":"wohnt","hint":"er-Endung -t."},{"prompt":"Wir [to learn] viel.","expected":"lernen","hint":"wir-Endung -en."},{"prompt":"Ihr [to drink] Kaffee.","expected":"trinkt","hint":"ihr-Endung -t."},{"prompt":"Wir [to go] ins Kino.","expected":"gehen","hint":"wir-Endung -en."},{"prompt":"Ihr [to eat] gerne Pizza.","expected":"esst","hint":"ihr-Endung -t."},{"prompt":"Sie [to read] ein Buch.","expected":"liest","hint":"Vokalwechsel e -> ie."},{"prompt":"Ich [to see] einen Film.","expected":"sehe","hint":"ich-Endung -e."},{"prompt":"Du [to write] einen Brief.","expected":"schreibst","hint":"Vokalwechsel e -> ei."},{"prompt":"Er [to play] Gitarre.","expected":"spielt","hint":"er-Endung -t."},{"prompt":"Wir [to help] dir.","expected":"helfen","hint":"wir-Endung -en."},{"prompt":"Ihr [to walk] im Park.","expected":"geht","hint":"ihr-Endung -t."},{"prompt":"Sie [to learn] Deutsch.","expected":"lernen","hint":"Sie-Endung -en."},{"prompt":"Ich [to buy] ein Auto.","expected":"kaufe","hint":"ich-Endung -e."},{"prompt":"Du [to drink] Wasser.","expected":"trinkst","hint":"Vokalwechsel e -> i."},{"prompt":"Er [to work] in einer Firma.","expected":"arbeitet","hint":"er-Endung -et."},{"prompt":"Wir [to travel] nach Spanien.","expected":"reisen","hint":"wir-Endung -en."},{"prompt":"Ihr [to sing] ein Lied.","expected":"singt","hint":"ihr-Endung -t."},{"prompt":"Sie [to run] schnell.","expected":"laufen","hint":"Sie-Endung -en."}]}', 13),
('de', 'A1', 'writing', 'Fragewörter', 'Question Words', 'W-Fragen bilden.', 'Forming W-questions.', '{"type":"type_word","instructions":"Tippen Sie das Fragewort.","exercises":[{"prompt":"[Who] bist du?","expected":"Wer","hint":"Person."},{"prompt":"[Where] wohnst du?","expected":"Wo","hint":"Ort."},{"prompt":"[What] machst du?","expected":"Was","hint":"Sache."},{"prompt":"[How] geht es dir?","expected":"Wie","hint":"Zustand."},{"prompt":"[When] kommst du?","expected":"Wann","hint":"Zeit."},{"prompt":"[Why] bist du spät?","expected":"Warum","hint":"Grund."},{"prompt":"[When] hast du Zeit?","expected":"Wann","hint":"Zeitpunkt."},{"prompt":"[Which] Buch liest du?","expected":"Welches","hint":"Auswahl."},{"prompt":"[How] geht es dir?","expected":"Wie","hint":"Zustand."},{"prompt":"[What kind of] Musik hörst du?","expected":"Welche","hint":"Kategorie."},{"prompt":"[Whose] Tasche ist das?","expected":"Wessen","hint":"Besitz."},{"prompt":"[How many] Äpfel hast du?","expected":"Wie viele","hint":"Anzahl."},{"prompt":"[What time] ist es?","expected":"Wie spät","hint":"Uhrzeit."},{"prompt":"[What color] ist dein Auto?","expected":"Welche Farbe","hint":"Eigenschaft."},{"prompt":"[Which] Film möchtest du sehen?","expected":"Welchen","hint":"Auswahl."},{"prompt":"[What] ist dein Lieblingsessen?","expected":"Was","hint":"Sache."},{"prompt":"[Where] sind deine Freunde?","expected":"Wo","hint":"Ort."},{"prompt":"[How much] kostet das?","expected":"Wie viel","hint":"Preis."},{"prompt":"[Who] hat das gesagt?","expected":"Wer","hint":"Person."},{"prompt":"[How long] dauert der Film?","expected":"Wie lange","hint":"Dauer."},{"prompt":"[What] ist dein Hobby?","expected":"Was","hint":"Aktivität."}]}', 14),
('de', 'A1', 'writing', 'Farben und Adjektive', 'Colors and Adjectives', 'Gegenteile schreiben.', 'Writing opposites.', '{"type":"type_word","instructions":"Schreiben Sie das Gegenteil.","exercises":[{"prompt":"groß <-> ...","expected":"klein","hint":"Small."},{"prompt":"gut <-> ...","expected":"schlecht","hint":"Bad."},{"prompt":"schön <-> ...","expected":"hässlich","hint":"Ugly."},{"prompt":"hell <-> ...","expected":"dunkel","hint":"Dark."},{"prompt":"alt <-> ...","expected":"jung","hint":"Young."},{"prompt":"warm <-> ...","expected":"kalt","hint":"Cold."},{"prompt":"hell <-> ...","expected":"dunkel","hint":"Dark."},{"prompt":"schnell <-> ...","expected":"langsam","hint":"Slow."},{"prompt":"freundlich <-> ...","expected":"unfreundlich","hint":"Unfriendly."},{"prompt":"reich <-> ...","expected":"arm","hint":"Poor."},{"prompt":"sauber <-> ...","expected":"schmutzig","hint":"Dirty."},{"prompt":"leicht <-> ...","expected":"schwierig","hint":"Difficult."},{"prompt":"früh <-> ...","expected":"spät","hint":"Late."},{"prompt":"freund <-> ...","expected":"Feind","hint":"Enemy."},{"prompt":"voll <-> ...","expected":"leer","hint":"Empty."},{"prompt":"hart <-> ...","expected":"weich","hint":"Soft."},{"prompt":"kurz <-> ...","expected":"lang","hint":"Long."},{"prompt":"süß <-> ...","expected":"sauer","hint":"Sour."},{"prompt":"jung <-> ...","expected":"alt","hint":"Old."},{"prompt":"offen <-> ...","expected":"geschlossen","hint":"Closed."}]}', 15);
